  "14-zero-downtime-blue-green": {
    title: "Zero-Downtime Blue-Green Deployments",
    questions: [
      { q: "What is a blue-green deployment?", options: ["a) Deploying to blue AWS regions and green AWS regions", "b) Maintaining two identical environments (blue=current, green=new), switching traffic between them", "c) A canary deployment with color-coded stages", "d) A deployment strategy that uses blue and green subnets"], answer: "b" },
      { q: "What is the main benefit of blue-green deployments?", options: ["a) Reduces infrastructure cost by 50%", "b) Enables zero-downtime releases with instant rollback capability", "c) Eliminates the need for load balancers", "d) Reduces the number of instances needed"], answer: "b" },
      { q: "How does traffic switching work in an ALB-based blue-green deployment?", options: ["a) Changing the DNS record to point to the new target group", "b) Updating the ALB listener rule to forward traffic to the new (green) target group", "c) Stopping the blue target group instances", "d) Updating security group rules"], answer: "b" },
      { q: "What is `create_before_destroy` in a Terraform lifecycle block used for in blue-green?", options: ["a) Creates all resources before planning", "b) Creates the new (green) resource before destroying the old (blue) one to avoid downtime", "c) Automatically switches traffic during apply", "d) Forces resource recreation on every apply"], answer: "b" },
      { q: "What are weighted Route53 records used for in blue-green deployments?", options: ["a) Load balancing based on server capacity", "b) Gradually shifting traffic percentage from blue to green during the transition", "c) Routing based on latency", "d) Failover routing between environments"], answer: "b" },
      { q: "What is a canary deployment?", options: ["a) Deploying only to production directly", "b) Sending a small percentage of traffic to the new version before full rollout", "c) Blue-green with automatic rollback", "d) Deploying using Docker containers only"], answer: "b" },
      { q: "How do you implement traffic shifting with Route53 weighted records in Terraform?", options: ["a) Set weight = 100 on both records", "b) Create two records with the same name but different weights summing to 100", "c) Use a single weighted record with multiple targets", "d) Use Route53 failover records with weights"], answer: "b" },
      { q: "What is the rollback procedure in a blue-green deployment?", options: ["a) Restore from backup", "b) Switch the ALB listener or DNS weight back to the blue (old) environment", "c) Redeploy the entire application", "d) Run terraform destroy on the green environment"], answer: "b" },
      { q: "What Terraform lifecycle argument prevents a resource from being destroyed if Terraform plans to do so?", options: ["a) no_destroy = true", "b) prevent_destroy = true", "c) keep_alive = true", "d) ignore_destroy = true"], answer: "b" },
      { q: "What is the `blue_weight` and `green_weight` pattern in Terraform blue-green?", options: ["a) IAM role weights for blue/green environments", "b) Route53 record weight variables controlling what percentage of traffic goes to each environment", "c) ASG scaling weights for blue/green", "d) ALB target group weights"], answer: "b" },
      { q: "What makes blue-green deployments more expensive than rolling deployments?", options: ["a) Blue-green requires more complex IAM roles", "b) Running two full sets of infrastructure simultaneously during the transition", "c) Blue-green uses more expensive instance types", "d) Blue-green requires dedicated VPCs"], answer: "b" },
      { q: "What is the purpose of a smoke test after switching to green?", options: ["a) Testing the deployment automation scripts", "b) Verifying the new version works correctly before decommissioning blue", "c) Testing network connectivity", "d) Verifying IAM permissions"], answer: "b" },
      { q: "What Terraform resources are typically needed for ALB-based blue-green? (Select all that apply)", options: ["a) Two target groups (blue and green)", "b) An ALB with a listener", "c) A listener rule pointing to the active target group", "d) Two separate ALBs"], answer: ["a", "b", "c"] },
      { q: "What are benefits of blue-green deployments? (Select all that apply)", options: ["a) Zero-downtime releases", "b) Instant rollback by switching traffic back", "c) Ability to test new version in production environment before cutover", "d) Reduces infrastructure cost"], answer: ["a", "b", "c"] },
      { q: "What should you verify before decommissioning the blue environment? (Select all that apply)", options: ["a) All health checks pass on green", "b) Smoke tests pass on green", "c) No in-flight requests are still being processed by blue", "d) Blue environment has passed a 24-hour soak test"], answer: ["a", "b", "c"] },
      { q: "What Terraform variable pattern supports gradual traffic migration?", options: ["a) A boolean var.use_green", "b) Integer variables var.blue_weight and var.green_weight to set Route53 record weights", "c) A string var.active_environment = \"blue\" or \"green\"", "d) Both b and c are valid patterns"], answer: "d" },
      { q: "What is the `connection_draining_timeout` (deregistration delay) important for in blue-green?", options: ["a) Speeding up the blue-green switch", "b) Allowing in-flight requests on deregistered blue instances to complete before they are terminated", "c) Setting idle connection timeouts", "d) Configuring health check intervals"], answer: "b" },
      { q: "What is the difference between blue-green and rolling deployments?", options: ["a) Blue-green is always faster than rolling", "b) Blue-green switches all traffic at once (or gradually); rolling updates instances incrementally", "c) Rolling deployments have better rollback capabilities", "d) Blue-green only works with containers"], answer: "b" },
      { q: "What does setting `weight = 0` on a Route53 weighted record do?", options: ["a) Deletes the record", "b) Sends no traffic to that endpoint", "c) Uses the record as a fallback only", "d) Disables health checks on the record"], answer: "b" },
      { q: "What is feature flagging in the context of blue-green deployments?", options: ["a) Flagging infrastructure changes in Terraform", "b) Enabling/disabling application features independently of infrastructure deployments", "c) Labeling blue and green environments with tags", "d) Flagging failed deployments for investigation"], answer: "b" }
    ]
  },
